mapper.sql:
from aiw_portfolio p
where p.is_deleted = 0
  and p.owner_user_biz_id = #{criteria.ownerUserBizId}

    and p.portfolio_type = #{criteria.portfolioType}


    and p.status = #{criteria.status}

mapper.select:
select p.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
